import { useState, useEffect, useCallback } from "react";
import {
  collection,
  doc,
  addDoc,
  getDoc,
  getDocs,
  setDoc,
  updateDoc,
  deleteDoc,
  onSnapshot,
  serverTimestamp,
  query,
  orderBy,
  where,
} from "firebase/firestore";
import { db } from "../firebase";

export function useLeagues(user) {
  const [leagues, setLeagues] = useState([]);
  const [leaguesLoading, setLeaguesLoading] = useState(true);
  const [leagueError, setLeagueError] = useState(null);

  const genCode = () =>
    Math.random().toString(36).substring(2, 8).toUpperCase();

  /* Listen to user's memberships */
  useEffect(() => {
    if (!user) {
      setLeagues([]);
      setLeaguesLoading(false);
      return;
    }

    const q = query(
      collection(db, "users", user.uid, "memberships"),
      orderBy("joinedAt", "desc")
    );
    const unsub = onSnapshot(q, async (snap) => {
      const codes = snap.docs.map((d) => d.data().leagueCode);
      if (!codes.length) {
        setLeagues([]);
        setLeaguesLoading(false);
        return;
      }

      const leagueSnaps = await Promise.all(
        codes.map((c) => getDoc(doc(db, "leagues", c)))
      );
      const data = leagueSnaps
        .filter((s) => s.exists())
        .map((s) => ({ code: s.id, ...s.data() }));
      setLeagues(data);
      setLeaguesLoading(false);
    });
    return unsub;
  }, [user]);

  const createLeague = useCallback(
    async (name) => {
      if (!user) return null;
      setLeagueError(null);
      try {
        const code = genCode();
        // FIX: Use setDoc with code as doc ID directly — no addDoc + setDoc duplication
        await setDoc(doc(db, "leagues", code), {
          code,
          name: name.trim() || "My League",
          createdBy: user.uid,
          createdByName: user.displayName || user.email,
          createdAt: serverTimestamp(),
        });
        await setDoc(doc(db, "users", user.uid, "memberships", code), {
          leagueCode: code,
          leagueName: name.trim() || "My League",
          joinedAt: serverTimestamp(),
        });
        return code;
      } catch (err) {
        setLeagueError(err.message);
        return null;
      }
    },
    [user]
  );

  const joinLeague = useCallback(
    async (code, bracket) => {
      if (!user || !bracket) return false;
      setLeagueError(null);
      const trimmed = code.trim().toUpperCase();
      try {
        const leagueRef = doc(db, "leagues", trimmed);
        const leagueSnap = await getDoc(leagueRef);
        if (!leagueSnap.exists()) {
          setLeagueError("League not found. Check the code and try again.");
          return false;
        }

        // Check not already entered with this bracket
        const entriesQ = query(
          collection(db, "leagues", trimmed, "entries"),
          where("uid", "==", user.uid),
          where("bracketId", "==", bracket.id)
        );
        const existing = await getDocs(entriesQ);
        if (!existing.empty) {
          setLeagueError(
            "You've already entered this bracket into this league."
          );
          return false;
        }

        // Add entry (snapshot of predictions at time of submission)
        await addDoc(collection(db, "leagues", trimmed, "entries"), {
          uid: user.uid,
          bracketId: bracket.id,
          bracketName: bracket.name,
          displayName: user.displayName || user.email,
          predictions: bracket.predictions || {},
          joinedAt: serverTimestamp(),
          locked: true,
        });

        // Lock the bracket so it can't be edited
        await updateDoc(doc(db, "users", user.uid, "brackets", bracket.id), {
          locked: true,
        });

        // Add to memberships (merge = safe if already a member via a previous bracket)
        await setDoc(
          doc(db, "users", user.uid, "memberships", trimmed),
          {
            leagueCode: trimmed,
            leagueName: leagueSnap.data().name,
            joinedAt: serverTimestamp(),
          },
          { merge: true }
        );

        return true;
      } catch (err) {
        setLeagueError(err.message);
        return false;
      }
    },
    [user]
  );

  const leaveLeague = useCallback(
    async (code, entryId) => {
      if (!user) return;
      setLeagueError(null);
      try {
        if (entryId) {
          await deleteDoc(doc(db, "leagues", code, "entries", entryId));
        }
        // Only remove membership if user has no remaining entries in this league
        const remaining = await getDocs(
          query(
            collection(db, "leagues", code, "entries"),
            where("uid", "==", user.uid)
          )
        );
        if (remaining.empty) {
          await deleteDoc(doc(db, "users", user.uid, "memberships", code));
        }
      } catch (err) {
        setLeagueError(err.message);
      }
    },
    [user]
  );

  const getLeagueEntries = useCallback(async (code) => {
    try {
      const q = query(
        collection(db, "leagues", code, "entries"),
        orderBy("joinedAt", "asc")
      );
      const snap = await getDocs(q);
      return snap.docs.map((d) => ({ id: d.id, ...d.data() }));
    } catch {
      return [];
    }
  }, []);

  return {
    leagues,
    leaguesLoading,
    leagueError,
    setLeagueError,
    createLeague,
    joinLeague,
    leaveLeague,
    getLeagueEntries,
  };
}
