import React, { useState } from "react";
import { useAuth } from "./hooks/useAuth";
import { useBrackets } from "./hooks/useBrackets";
import { useLeagues } from "./hooks/useLeagues";
import { TABS } from "./data/stages";
import {
  buildR16Matchups,
  buildQFMatchups,
  buildSFMatchups,
  buildFinalMatchup,
} from "./utils/bracket";

import Header from "./components/Header/Header";
import NavTabs from "./components/NavTabs/NavTabs";
import LoginPage from "./components/LoginPage/LoginPage";
import BracketManager from "./components/BracketManager/BracketManager";
import GroupStage from "./components/GroupStage/GroupStage";
import RoundOf32 from "./components/RoundOf32/RoundOf32";
import MatchupStage from "./components/MatchupStage/MatchupStage";
import BracketView from "./components/BracketView/BracketView";
import LeaguePage from "./components/LeaguePage/LeaguePage";
import Leaderboard from "./components/Leaderboard/Leaderboard";

import "./App.css";

export default function App() {
  const { user, authLoading, login, signup, loginGoogle, logout } = useAuth();
  const {
    brackets,
    bracketsLoading,
    activeBracketId,
    activeBracket,
    setActiveBracketId,
    createBracket,
    renameBracket,
    deleteBracket,
    updatePredictions,
  } = useBrackets(user?.uid);
  const {
    leagues,
    leaguesLoading,
    leagueError,
    setLeagueError,
    createLeague,
    joinLeague,
    leaveLeague,
  } = useLeagues(user);

  const [activeTab, setActiveTab] = useState("brackets");

  if (authLoading) {
    return (
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "100vh",
          background: "#0b0e1a",
          color: "#E61D25",
          fontFamily: "'Bebas Neue',sans-serif",
          fontSize: "1.5rem",
          letterSpacing: "4px",
        }}
      >
        🏆 Loading…
      </div>
    );
  }

  if (!user) {
    return (
      <>
        <Header user={null} onLogout={null} />
        <LoginPage
          onLogin={login}
          onSignup={signup}
          onGoogleLogin={loginGoogle}
        />
      </>
    );
  }

  // ── Active bracket predictions ───────────────────────────────
  const predictions = activeBracket?.predictions || {};
  const locked = activeBracket?.locked || false;

  const updateStage = (stageId, data) => {
    if (!activeBracketId || locked) return;
    updatePredictions(activeBracketId, stageId, data);
  };

  // ── Bracket chain ────────────────────────────────────────────
  const r32Winners = predictions.r32Winners || [];
  const r16Winners = predictions.r16Winners || [];
  const qfWinners = predictions.qfWinners || [];
  const sfWinners = predictions.sfWinners || [];

  const r32Done = r32Winners.filter(Boolean).length === 16;
  const r16Done = r16Winners.filter(Boolean).length === 8;
  const qfDone = qfWinners.filter(Boolean).length === 4;
  const sfDone = sfWinners.filter(Boolean).length === 2;

  const r16Matchups = buildR16Matchups(r32Winners);
  const qfMatchups = buildQFMatchups(r16Winners);
  const sfMatchups = buildSFMatchups(qfWinners);
  const finalMatchups = buildFinalMatchup(sfWinners);

  const makePickHandler =
    (stageKey, matchups, downstreamKeys) => (idx, team) => {
      if (locked) return;
      const current = [
        ...(predictions[stageKey] || Array(matchups.length).fill(null)),
      ];
      while (current.length < matchups.length) current.push(null);
      current[idx] = current[idx]?.id === team.id ? null : team;
      updateStage(stageKey, current);
      downstreamKeys.forEach((k) => updateStage(k, []));
    };

  const pickR16 = makePickHandler("r16Winners", r16Matchups, [
    "qfWinners",
    "sfWinners",
    "final",
  ]);
  const pickQF = makePickHandler("qfWinners", qfMatchups, [
    "sfWinners",
    "final",
  ]);
  const pickSF = makePickHandler("sfWinners", sfMatchups, ["final"]);
  const pickFinal = (idx, team) => {
    if (locked) return;
    const current = [...(predictions.final || [null])];
    current[0] = current[0]?.id === team.id ? null : team;
    updateStage("final", current);
  };

  // ── No bracket yet — prompt creation ────────────────────────
  const noBracketTabs = ["leagues", "board", "brackets"];
  const needsBracket =
    !activeBracket && !noBracketTabs.includes(activeTab) && !bracketsLoading;

  const renderContent = () => {
    // Bracket management
    if (activeTab === "brackets") {
      return (
        <div>
          <div className="section-header">
            <h2 className="section-header__title">📁 My Brackets</h2>
            <p className="section-header__sub">
              Create multiple brackets. Locked brackets have been submitted to a
              league and cannot be edited.
            </p>
          </div>
          <BracketManager
            brackets={brackets}
            activeBracketId={activeBracketId}
            onSelect={setActiveBracketId}
            onCreate={createBracket}
            onRename={renameBracket}
            onDelete={deleteBracket}
          />
          {brackets.length === 0 && !bracketsLoading && (
            <p style={{ color: "var(--color-text-muted)", fontSize: "0.9rem" }}>
              Create your first bracket above, then head to Group Stage to start
              picking!
            </p>
          )}
        </div>
      );
    }

    if (activeTab === "leagues")
      return (
        <LeaguePage
          user={user}
          leagues={leagues}
          leaguesLoading={leaguesLoading}
          leagueError={leagueError}
          setLeagueError={setLeagueError}
          brackets={brackets}
          onCreate={createLeague}
          onJoin={joinLeague}
          onLeave={leaveLeague}
        />
      );
    if (activeTab === "board")
      return <Leaderboard leagues={leagues} currentUid={user.uid} />;
    if (activeTab === "view")
      return (
        <BracketView
          predictions={predictions}
          bracketName={activeBracket?.name}
          brackets={brackets}
          activeBracketId={activeBracketId}
          onSwitchBracket={setActiveBracketId}
        />
      );

    // Require an active bracket for prediction tabs
    if (needsBracket) {
      return (
        <div className="empty-state">
          <span className="empty-state__icon">📁</span>
          <h3 className="empty-state__title">No Bracket Selected</h3>
          <p className="empty-state__body">
            Go to My Brackets to create or select a bracket first.
          </p>
          <button
            className="btn btn--gold"
            style={{ marginTop: "1rem" }}
            onClick={() => setActiveTab("brackets")}
          >
            Go to My Brackets
          </button>
        </div>
      );
    }

    return (
      <>
        {/* Active bracket indicator */}
        {activeBracket && (
          <div
            className={`bracket-indicator${
              locked ? " bracket-indicator--locked" : ""
            }`}
          >
            <span className="bracket-indicator__name">
              Editing: <strong>{activeBracket.name}</strong>
            </span>
            {locked ? (
              <span className="bracket-indicator__locked">
                🔒 Locked — submitted to a league
              </span>
            ) : (
              <button
                className="btn btn--ghost btn--sm"
                onClick={() => setActiveTab("brackets")}
              >
                Switch
              </button>
            )}
          </div>
        )}

        {activeTab === "group" && (
          <GroupStage predictions={predictions} onUpdate={updateStage} />
        )}
        {activeTab === "r32" && (
          <RoundOf32 predictions={predictions} onUpdate={updateStage} />
        )}
        {activeTab === "r16" && (
          <MatchupStage
            icon="🎯"
            label="Round of 16"
            description="Winners from the Round of 32. Click to advance."
            matchups={r16Matchups}
            winners={r16Winners}
            onPickWinner={pickR16}
            prevDone={r32Done}
            prevStageName="Round of 32"
          />
        )}
        {activeTab === "qf" && (
          <MatchupStage
            icon="⚔️"
            label="Quarter-Finals"
            description="The last 8 teams. Pick your survivors."
            matchups={qfMatchups}
            winners={qfWinners}
            onPickWinner={pickQF}
            prevDone={r16Done}
            prevStageName="Round of 16"
          />
        )}
        {activeTab === "sf" && (
          <MatchupStage
            icon="🔥"
            label="Semi-Finals"
            description="Four teams remain. Who reaches the Final?"
            matchups={sfMatchups}
            winners={sfWinners}
            onPickWinner={pickSF}
            prevDone={qfDone}
            prevStageName="Quarter-Finals"
          />
        )}
        {activeTab === "final" && (
          <MatchupStage
            icon="🏆"
            label="The Final — July 19, MetLife Stadium"
            description="Pick your 2026 World Cup Champion."
            matchups={finalMatchups}
            winners={predictions.final || []}
            onPickWinner={pickFinal}
            prevDone={sfDone}
            prevStageName="Semi-Finals"
          />
        )}
      </>
    );
  };

  return (
    <>
      <Header
        user={{ name: user.displayName || user.email }}
        onLogout={logout}
      />
      <NavTabs tabs={TABS} activeTab={activeTab} onSelect={setActiveTab} />
      <main className="app-content">{renderContent()}</main>
    </>
  );
}
