import React, { useState, useEffect } from "react";
import "./LeaguePage.css";

export default function LeaguePage({
  user,
  leagues,
  leaguesLoading,
  leagueError,
  setLeagueError,
  brackets,
  onCreate,
  onJoin,
  onLeave,
}) {
  const [view, setView] = useState("list");
  const [leagueName, setLeagueName] = useState("");
  const [joinCode, setJoinCode] = useState("");
  const [selectedBracketId, setSelectedBracketId] = useState("");
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(null);
  // Per-league entries cache: { [code]: entry[] }
  const [entriesMap, setEntriesMap] = useState({});
  const [loadingEntries, setLoadingEntries] = useState({});

  // Load entries for each league the user is in
  useEffect(() => {
    leagues.forEach(async (league) => {
      if (entriesMap[league.code] !== undefined) return; // already loaded
      setLoadingEntries((p) => ({ ...p, [league.code]: true }));
      try {
        const { collection, query, getDocs, orderBy } = await import(
          "firebase/firestore"
        );
        const { db } = await import("../../firebase");
        const q = query(
          collection(db, "leagues", league.code, "entries"),
          orderBy("joinedAt", "asc")
        );
        const snap = await getDocs(q);
        const entries = snap.docs.map((d) => ({ id: d.id, ...d.data() }));
        setEntriesMap((p) => ({ ...p, [league.code]: entries }));
      } catch {
        setEntriesMap((p) => ({ ...p, [league.code]: [] }));
      } finally {
        setLoadingEntries((p) => ({ ...p, [league.code]: false }));
      }
    });
  }, [leagues]);

  const refreshEntries = async (code) => {
    try {
      const { collection, query, getDocs, orderBy } = await import(
        "firebase/firestore"
      );
      const { db } = await import("../../firebase");
      const q = query(
        collection(db, "leagues", code, "entries"),
        orderBy("joinedAt", "asc")
      );
      const snap = await getDocs(q);
      setEntriesMap((p) => ({
        ...p,
        [code]: snap.docs.map((d) => ({ id: d.id, ...d.data() })),
      }));
    } catch {}
  };

  const handleCreate = async () => {
    if (!leagueName.trim()) return;
    setLoading(true);
    const code = await onCreate(leagueName);
    setLoading(false);
    if (code) {
      setLeagueName("");
      setView("list");
    }
  };

  const handleJoin = async () => {
    if (!joinCode.trim() || !selectedBracketId) return;
    const bracket = brackets.find((b) => b.id === selectedBracketId);
    if (!bracket) return;
    setLoading(true);
    const ok = await onJoin(joinCode, bracket);
    setLoading(false);
    if (ok) {
      setJoinCode("");
      setSelectedBracketId("");
      setView("list");
      // Clear entries cache for this league so it reloads
      setEntriesMap((p) => {
        const n = { ...p };
        delete n[joinCode.trim().toUpperCase()];
        return n;
      });
    }
  };

  const copyCode = (code) => {
    navigator.clipboard.writeText(code);
    setCopied(code);
    setTimeout(() => setCopied(null), 2000);
  };

  if (leaguesLoading)
    return (
      <div className="lp">
        <p className="lp__loading">Loading leagues…</p>
      </div>
    );

  return (
    <div className="lp">
      <div className="section-header">
        <h2 className="section-header__title">🏟️ My Leagues</h2>
        <p className="section-header__sub">
          Create leagues, invite friends, and enter any of your brackets. Each
          league has its own leaderboard.
        </p>
      </div>

      <div className="lp__actions">
        <button
          className={`btn${view === "create" ? " btn--gold" : " btn--outline"}`}
          onClick={() => {
            setView(view === "create" ? "list" : "create");
            setLeagueError(null);
          }}
        >
          ＋ Create League
        </button>
        <button
          className={`btn${view === "join" ? " btn--gold" : " btn--outline"}`}
          onClick={() => {
            setView(view === "join" ? "list" : "join");
            setLeagueError(null);
          }}
        >
          🔗 Join League
        </button>
      </div>

      {leagueError && <p className="lp__error">{leagueError}</p>}

      {view === "create" && (
        <div className="lp__form">
          <h3 className="lp__form-title">Create a New League</h3>
          <div className="field">
            <label className="field__label">League Name</label>
            <input
              className="field__input"
              placeholder="e.g. The Lads FC"
              value={leagueName}
              onChange={(e) => setLeagueName(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleCreate()}
              autoFocus
            />
          </div>
          <button
            className="btn btn--gold"
            onClick={handleCreate}
            disabled={loading || !leagueName.trim()}
          >
            {loading ? "Creating…" : "Create League"}
          </button>
        </div>
      )}

      {view === "join" && (
        <div className="lp__form">
          <h3 className="lp__form-title">Join a League</h3>
          <div className="field">
            <label className="field__label">Invite Code</label>
            <input
              className="field__input lp__code-input"
              placeholder="6-character code"
              value={joinCode}
              onChange={(e) => setJoinCode(e.target.value.toUpperCase())}
              maxLength={6}
              autoFocus
            />
          </div>
          <div className="field">
            <label className="field__label">Enter with which bracket?</label>
            {brackets.length === 0 ? (
              <p className="lp__no-brackets">
                No brackets yet. Create one in the bracket tabs first.
              </p>
            ) : (
              <div className="lp__bracket-select">
                {brackets.map((b) => (
                  <button
                    key={b.id}
                    className={`lp__bracket-opt${
                      selectedBracketId === b.id
                        ? " lp__bracket-opt--active"
                        : ""
                    }`}
                    onClick={() => setSelectedBracketId(b.id)}
                  >
                    <span>{b.name}</span>
                    {b.locked && <span className="lp__locked">🔒</span>}
                  </button>
                ))}
              </div>
            )}
          </div>
          {selectedBracketId &&
            !brackets.find((b) => b.id === selectedBracketId)?.locked && (
              <p className="lp__lock-warning">
                ⚠️ Your bracket will be <strong>locked</strong> once you join.
              </p>
            )}
          <button
            className="btn btn--gold"
            onClick={handleJoin}
            disabled={
              loading ||
              !joinCode.trim() ||
              joinCode.length < 6 ||
              !selectedBracketId ||
              brackets.length === 0
            }
          >
            {loading ? "Joining…" : "Join League"}
          </button>
        </div>
      )}

      {leagues.length === 0 && view === "list" ? (
        <div className="empty-state">
          <span className="empty-state__icon">🏟️</span>
          <h3 className="empty-state__title">No Leagues Yet</h3>
          <p className="empty-state__body">
            Create a league and invite friends, or join one with an invite code.
          </p>
        </div>
      ) : (
        <div className="lp__leagues">
          {leagues.map((league) => (
            <LeagueCard
              key={league.code}
              league={league}
              currentUid={user.uid}
              brackets={brackets}
              entries={entriesMap[league.code] || []}
              entriesLoading={loadingEntries[league.code]}
              onJoin={async (bracket) => {
                const ok = await onJoin(league.code, bracket);
                if (ok) await refreshEntries(league.code);
                return ok;
              }}
              onLeave={async (entryId) => {
                await onLeave(league.code, entryId);
                await refreshEntries(league.code);
              }}
              onCopy={copyCode}
              copied={copied}
              leagueError={leagueError}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function LeagueCard({
  league,
  currentUid,
  brackets,
  entries,
  entriesLoading,
  onJoin,
  onLeave,
  onCopy,
  copied,
}) {
  const [expanded, setExpanded] = useState(false);
  const [joinBracketId, setJoinBracketId] = useState("");
  const [loading, setLoading] = useState(false);

  const myEntries = entries.filter((e) => e.uid === currentUid);

  const handleEnterBracket = async () => {
    const bracket = brackets.find((b) => b.id === joinBracketId);
    if (!bracket) return;
    setLoading(true);
    await onJoin(bracket);
    setLoading(false);
    setJoinBracketId("");
  };

  return (
    <div className="lp__league-card">
      <div className="lp__league-header" onClick={() => setExpanded((e) => !e)}>
        <div>
          <div className="lp__league-name">{league.name}</div>
          <div className="lp__league-meta">
            Code: <span className="lp__code">{league.code}</span>
            {" · "}
            {myEntries.length} bracket{myEntries.length !== 1 ? "s" : ""}{" "}
            entered
          </div>
        </div>
        <div className="lp__league-header-right">
          <button
            className="btn btn--ghost btn--sm"
            onClick={(e) => {
              e.stopPropagation();
              onCopy(league.code);
            }}
          >
            {copied === league.code ? "✓ Copied" : "Copy Code"}
          </button>
          <span className="lp__expand">{expanded ? "▲" : "▼"}</span>
        </div>
      </div>

      {expanded && (
        <div className="lp__league-body">
          {entriesLoading && (
            <p
              style={{ color: "var(--color-text-muted)", fontSize: "0.82rem" }}
            >
              Loading entries…
            </p>
          )}

          {myEntries.length > 0 && (
            <div className="lp__my-entries">
              <div className="lp__entries-label">Your entries:</div>
              {myEntries.map((entry) => (
                <div key={entry.id} className="lp__entry-row">
                  <span className="lp__entry-name">{entry.bracketName}</span>
                  <span className="lp__entry-locked">🔒 Locked</span>
                  <button
                    className="btn btn--danger btn--sm"
                    onClick={() => {
                      if (window.confirm("Remove this entry from the league?"))
                        onLeave(entry.id);
                    }}
                  >
                    Remove
                  </button>
                </div>
              ))}
            </div>
          )}

          <div className="lp__add-entry">
            <div className="lp__entries-label">Enter another bracket:</div>
            {brackets.length === 0 ? (
              <p className="lp__no-brackets">No brackets yet.</p>
            ) : (
              <div className="lp__bracket-select">
                {brackets.map((b) => (
                  <button
                    key={b.id}
                    className={`lp__bracket-opt${
                      joinBracketId === b.id ? " lp__bracket-opt--active" : ""
                    }`}
                    onClick={() => setJoinBracketId(b.id)}
                  >
                    <span>{b.name}</span>
                    {b.locked && <span className="lp__locked">🔒</span>}
                  </button>
                ))}
              </div>
            )}
            {joinBracketId &&
              !brackets.find((b) => b.id === joinBracketId)?.locked && (
                <p className="lp__lock-warning">
                  ⚠️ Bracket will be locked once submitted.
                </p>
              )}
            <button
              className="btn btn--outline btn--sm"
              style={{ marginTop: "0.5rem" }}
              onClick={handleEnterBracket}
              disabled={loading || !joinBracketId}
            >
              {loading ? "Submitting…" : "Submit Bracket"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
