import React, { useState } from "react";
import "./BracketManager.css";

/**
 * BracketManager — sidebar/panel for managing multiple brackets.
 * Lets user create, rename, delete, and switch between brackets.
 */
export default function BracketManager({
  brackets,
  activeBracketId,
  onSelect,
  onCreate,
  onRename,
  onDelete,
}) {
  const [creating, setCreating] = useState(false);
  const [newName, setNewName] = useState("");
  const [renamingId, setRenamingId] = useState(null);
  const [renameVal, setRenameVal] = useState("");

  const handleCreate = async () => {
    if (!newName.trim()) return;
    await onCreate(newName);
    setNewName("");
    setCreating(false);
  };

  const handleRename = async (id) => {
    if (!renameVal.trim()) return;
    await onRename(id, renameVal);
    setRenamingId(null);
  };

  return (
    <div className="bm">
      <div className="bm__header">
        <span className="bm__title">My Brackets</span>
        <button
          className="bm__add-btn"
          onClick={() => setCreating(true)}
          title="New bracket"
        >
          ＋
        </button>
      </div>

      {/* Create new */}
      {creating && (
        <div className="bm__create">
          <input
            className="bm__input"
            placeholder="Bracket name…"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleCreate();
              if (e.key === "Escape") setCreating(false);
            }}
            autoFocus
          />
          <div className="bm__create-actions">
            <button className="btn btn--gold btn--sm" onClick={handleCreate}>
              Create
            </button>
            <button
              className="btn btn--ghost btn--sm"
              onClick={() => setCreating(false)}
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bracket list */}
      <div className="bm__list">
        {brackets.length === 0 && !creating && (
          <p className="bm__empty">No brackets yet. Create one above.</p>
        )}
        {brackets.map((b) => (
          <div
            key={b.id}
            className={`bm__item${
              b.id === activeBracketId ? " bm__item--active" : ""
            }${b.locked ? " bm__item--locked" : ""}`}
            onClick={() => renamingId !== b.id && onSelect(b.id)}
          >
            {renamingId === b.id ? (
              <div className="bm__rename" onClick={(e) => e.stopPropagation()}>
                <input
                  className="bm__input"
                  value={renameVal}
                  onChange={(e) => setRenameVal(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") handleRename(b.id);
                    if (e.key === "Escape") setRenamingId(null);
                  }}
                  autoFocus
                />
                <div className="bm__create-actions">
                  <button
                    className="btn btn--gold btn--sm"
                    onClick={() => handleRename(b.id)}
                  >
                    Save
                  </button>
                  <button
                    className="btn btn--ghost btn--sm"
                    onClick={() => setRenamingId(null)}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            ) : (
              <>
                <div className="bm__item-left">
                  <span className="bm__item-name">
                    {b.id === activeBracketId && "▶ "}
                    {b.name}
                  </span>
                  {b.locked && (
                    <span className="bm__locked-badge">
                      🔒 Locked{b.id === activeBracketId ? " · Active" : ""}
                    </span>
                  )}
                </div>
                <div
                  className="bm__item-actions"
                  onClick={(e) => e.stopPropagation()}
                >
                  {!b.locked && (
                    <button
                      className="bm__icon-btn"
                      title="Rename"
                      onClick={() => {
                        setRenamingId(b.id);
                        setRenameVal(b.name);
                      }}
                    >
                      ✏️
                    </button>
                  )}
                  <button
                    className="bm__icon-btn bm__icon-btn--danger"
                    title="Delete"
                    onClick={() => {
                      if (window.confirm(`Delete "${b.name}"?`)) onDelete(b.id);
                    }}
                  >
                    🗑️
                  </button>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
