import React, { useState } from "react";
import "./LoginPage.css";

export default function LoginPage({ onLogin, onSignup, onGoogleLogin }) {
  const [mode, setMode] = useState("login");
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const update = (key) => (e) =>
    setForm((f) => ({ ...f, [key]: e.target.value }));

  const friendlyError = (err) => {
    const code = err?.code || "";
    if (code.includes("user-not-found"))
      return "No account found with that email.";
    if (code.includes("wrong-password")) return "Incorrect password.";
    if (code.includes("email-already"))
      return "An account with this email already exists.";
    if (code.includes("weak-password"))
      return "Password must be at least 6 characters.";
    if (code.includes("invalid-email"))
      return "Please enter a valid email address.";
    if (code.includes("popup-closed")) return "Google sign-in was cancelled.";
    if (code.includes("network-request"))
      return "Network error — check your connection.";
    return err?.message || "Something went wrong.";
  };

  const handleSubmit = async () => {
    setError("");
    if (!form.email || !form.password)
      return setError("Email and password are required.");
    if (mode === "signup" && !form.name)
      return setError("Please enter your name.");
    setLoading(true);
    try {
      if (mode === "signup") {
        await onSignup(form.email, form.password, form.name.trim());
      } else {
        await onLogin(form.email, form.password);
      }
    } catch (err) {
      setError(friendlyError(err));
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    setError("");
    setLoading(true);
    try {
      await onGoogleLogin();
    } catch (err) {
      setError(friendlyError(err));
    } finally {
      setLoading(false);
    }
  };

  const toggleMode = () => {
    setMode((m) => (m === "login" ? "signup" : "login"));
    setError("");
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-card__hero">
          <span className="login-card__trophy">🏆</span>
          <h1 className="login-card__title">FIFA World Cup</h1>
          <p className="login-card__subtitle">2026 · USA · Canada · Mexico</p>
        </div>

        <h2 className="login-card__form-title">
          {mode === "login" ? "Sign in to your bracket" : "Create your bracket"}
        </h2>

        {/* Google button */}
        <button
          className="btn-google"
          onClick={handleGoogle}
          disabled={loading}
        >
          <svg className="btn-google__icon" viewBox="0 0 24 24">
            <path
              fill="#4285F4"
              d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
            />
            <path
              fill="#34A853"
              d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
            />
            <path
              fill="#FBBC05"
              d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"
            />
            <path
              fill="#EA4335"
              d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
            />
          </svg>
          Continue with Google
        </button>

        <div className="login-card__divider">
          <span>or</span>
        </div>

        {mode === "signup" && (
          <div className="field">
            <label className="field__label" htmlFor="name">
              Full name
            </label>
            <input
              id="name"
              className="field__input"
              placeholder="Your name"
              value={form.name}
              onChange={update("name")}
              onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            />
          </div>
        )}

        <div className="field">
          <label className="field__label" htmlFor="email">
            Email
          </label>
          <input
            id="email"
            type="email"
            className="field__input"
            placeholder="you@example.com"
            value={form.email}
            onChange={update("email")}
            onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            autoFocus
          />
        </div>

        <div className="field">
          <label className="field__label" htmlFor="password">
            Password
          </label>
          <input
            id="password"
            type="password"
            className="field__input"
            placeholder="••••••••"
            value={form.password}
            onChange={update("password")}
            onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
          />
        </div>

        {error && (
          <p className="login-card__error" role="alert">
            {error}
          </p>
        )}

        <button
          className="btn btn--gold btn--lg login-card__submit"
          onClick={handleSubmit}
          disabled={loading}
        >
          {loading ? "…" : mode === "login" ? "Sign In" : "Create Account"}
        </button>

        <p className="login-card__switch">
          {mode === "login" ? "No account? " : "Already registered? "}
          <button className="login-card__switch-btn" onClick={toggleMode}>
            {mode === "login" ? "Create an account" : "Sign in"}
          </button>
        </p>
      </div>
    </div>
  );
}
