import React, { useEffect, useState } from "react";
import {
  collection,
  query,
  orderBy,
  onSnapshot,
  doc,
  getDoc,
} from "firebase/firestore";
import { db } from "../../firebase";
import {
  scorePredictions,
  countPicks,
  MAX_POINTS,
  STAGE_LABELS,
} from "../../utils/scoring";
import "./Leaderboard.css";

export default function Leaderboard({ leagues, currentUid }) {
  const [selectedCode, setSelectedCode] = useState(null);
  const [entries, setEntries] = useState([]);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [selected, setSelected] = useState(null);

  // Auto-select first league
  useEffect(() => {
    if (leagues.length && !selectedCode) setSelectedCode(leagues[0].code);
  }, [leagues]);

  // Load entries for selected league (real-time)
  useEffect(() => {
    if (!selectedCode) return;
    setLoading(true);
    setEntries([]);
    setSelected(null);

    const q = query(
      collection(db, "leagues", selectedCode, "entries"),
      orderBy("joinedAt", "asc")
    );
    const unsub = onSnapshot(q, (snap) => {
      setEntries(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
      setLoading(false);
    });

    // Load results if they exist
    getDoc(doc(db, "leagues", selectedCode, "meta", "results"))
      .then((s) => {
        if (s.exists()) setResults(s.data());
        else setResults(null);
      })
      .catch(() => setResults(null));

    return unsub;
  }, [selectedCode]); // eslint-disable-line

  if (!leagues.length) {
    return (
      <div className="lb">
        <div className="empty-state">
          <span className="empty-state__icon">📊</span>
          <h3 className="empty-state__title">No Leagues Yet</h3>
          <p className="empty-state__body">
            Join or create a league to see the leaderboard.
          </p>
        </div>
      </div>
    );
  }

  // Score and sort entries
  const scored = entries
    .map((e) => {
      const picks = countPicks(e.predictions || {});
      const score = results
        ? scorePredictions(e.predictions || {}, results)
        : null;
      return { ...e, picks, score };
    })
    .sort((a, b) => {
      if (a.score && b.score) return b.score.total - a.score.total;
      return b.picks.total - a.picks.total;
    });

  const selectedEntry = selected ? scored.find((e) => e.id === selected) : null;

  return (
    <div className="lb">
      <div className="section-header">
        <h2 className="section-header__title">📊 Leaderboard</h2>
        <p className="section-header__sub">
          {results
            ? "Scored against official results."
            : "Scoring activates when official results are set. Showing pick counts for now."}
        </p>
      </div>

      {/* League selector */}
      <div className="lb__league-tabs">
        {leagues.map((l) => (
          <button
            key={l.code}
            className={`lb__league-tab${
              selectedCode === l.code ? " lb__league-tab--active" : ""
            }`}
            onClick={() => {
              setSelectedCode(l.code);
              setSelected(null);
            }}
          >
            {l.name}
            <span className="lb__league-code">{l.code}</span>
          </button>
        ))}
      </div>

      {loading ? (
        <p className="lb__loading">Loading entries…</p>
      ) : entries.length === 0 ? (
        <div className="empty-state" style={{ paddingTop: "2rem" }}>
          <span className="empty-state__icon">🏟️</span>
          <h3 className="empty-state__title">No entries yet</h3>
          <p className="empty-state__body">
            Share the code <strong>{selectedCode}</strong> so friends can join
            and submit brackets.
          </p>
        </div>
      ) : (
        <>
          {/* Table */}
          <div className="lb__table">
            <div className="lb__header">
              <span>#</span>
              <span>Player · Bracket</span>
              <span>Picks</span>
              {results && <span>Points</span>}
              <span>Champion</span>
              <span />
            </div>

            {scored.map((entry, idx) => {
              const isMe = entry.uid === currentUid;
              const champion = (entry.predictions?.final || [])[0] || null;
              return (
                <div
                  key={entry.id}
                  className={`lb__row${isMe ? " lb__row--me" : ""}${
                    idx === 0 ? " lb__row--first" : ""
                  }${selected === entry.id ? " lb__row--selected" : ""}`}
                  onClick={() =>
                    setSelected(selected === entry.id ? null : entry.id)
                  }
                >
                  <span className="lb__rank">
                    {idx === 0
                      ? "🥇"
                      : idx === 1
                      ? "🥈"
                      : idx === 2
                      ? "🥉"
                      : idx + 1}
                  </span>
                  <span className="lb__name">
                    <span className="lb__name-main">{entry.displayName}</span>
                    <span className="lb__bracket-name">
                      {entry.bracketName}
                    </span>
                    {isMe && <span className="lb__you">You</span>}
                  </span>
                  <span className="lb__picks">
                    <PickBar picks={entry.picks} />
                  </span>
                  {results && (
                    <span className="lb__pts">
                      <span className="lb__pts-val">
                        {entry.score?.total || 0}
                      </span>
                      <span className="lb__pts-max">/{MAX_POINTS}</span>
                    </span>
                  )}
                  <span className="lb__champ">
                    {champion ? (
                      <>
                        {champion.flag} {champion.name}
                      </>
                    ) : (
                      <span className="lb__champ-tbd">—</span>
                    )}
                  </span>
                  <span className="lb__expand">
                    {selected === entry.id ? "▲" : "▼"}
                  </span>
                </div>
              );
            })}
          </div>

          {/* Expanded entry */}
          {selectedEntry && (
            <div className="lb__detail">
              <h3 className="lb__detail-title">
                {selectedEntry.displayName} — {selectedEntry.bracketName}
                {selectedEntry.uid === currentUid && " (You)"}
              </h3>
              {results && selectedEntry.score && (
                <div className="lb__score-breakdown">
                  {selectedEntry.score.breakdown.map((b) => (
                    <div key={b.stage} className="lb__score-row">
                      <span className="lb__score-stage">
                        {STAGE_LABELS[b.stage]}
                      </span>
                      <span className="lb__score-correct">
                        {b.correct} correct
                      </span>
                      <span className="lb__score-pts">+{b.pts} pts</span>
                    </div>
                  ))}
                  <div className="lb__score-total">
                    Total: {selectedEntry.score.total} / {MAX_POINTS} pts
                  </div>
                </div>
              )}
              <PredictionSummary
                predictions={selectedEntry.predictions || {}}
              />
            </div>
          )}
        </>
      )}
    </div>
  );
}

function PickBar({ picks }) {
  const stages = [
    { label: "R32", val: picks.r32, max: 16 },
    { label: "R16", val: picks.r16, max: 8 },
    { label: "QF", val: picks.qf, max: 4 },
    { label: "SF", val: picks.sf, max: 2 },
    { label: "F", val: picks.fin, max: 1 },
  ];
  return (
    <div className="pick-bar">
      {stages.map((s) => (
        <div
          key={s.label}
          className="pick-bar__stage"
          title={`${s.label}: ${s.val}/${s.max}`}
        >
          <div
            className="pick-bar__fill"
            style={{ height: `${Math.round((s.val / s.max) * 100)}%` }}
          />
        </div>
      ))}
    </div>
  );
}

function PredictionSummary({ predictions }) {
  const stages = [
    { key: "r32Winners", label: "Round of 32", icon: "🏟️" },
    { key: "r16Winners", label: "Round of 16", icon: "🎯" },
    { key: "qfWinners", label: "Quarter-Finals", icon: "⚔️" },
    { key: "sfWinners", label: "Semi-Finals", icon: "🔥" },
    { key: "final", label: "Champion", icon: "🏆" },
  ];
  return (
    <div className="lb__pred-summary">
      {stages.map(({ key, label, icon }) => {
        const teams = (predictions[key] || []).filter(Boolean);
        if (!teams.length) return null;
        return (
          <div key={key} className="lb__pred-section">
            <div className="lb__pred-label">
              {icon} {label}
            </div>
            <div className="lb__pred-teams">
              {teams.map((t, i) => (
                <span key={`${key}-${t.id}-${i}`} className="lb__pred-badge">
                  {t.flag} {t.name}
                </span>
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}
