/**
 * scoring.js — points system for prediction accuracy.
 *
 * Points are awarded when a user's predicted winner matches
 * the actual winner stored in a "results" document.
 * For now (tournament in progress), we score against whoever
 * the user themselves picked as champion and propagate backwards —
 * or an admin can set official results later.
 *
 * Points per stage:
 *   R32  correct pick: 1 pt  (16 matches × 1 = 16 max)
 *   R16  correct pick: 2 pts (8  matches × 2 = 16 max)
 *   QF   correct pick: 4 pts (4  matches × 4 = 16 max)
 *   SF   correct pick: 8 pts (2  matches × 8 = 16 max)
 *   Final winner:     16 pts (1  match  × 16 = 16 max)
 *   Champion:         32 pts                  (32 max)
 *
 *   Maximum total: 112 pts
 */

const STAGE_POINTS = {
  r32Winners: 1,
  r16Winners: 2,
  qfWinners:  4,
  sfWinners:  8,
  final:      16,
};

/**
 * Score a user's predictions against official results.
 *
 * @param {object} predictions — user's predictions object
 * @param {object} results     — official results (same shape as predictions)
 * @returns {{ total, breakdown: { stage, pts, correct, possible }[] }}
 */
export function scorePredictions(predictions, results) {
  if (!results || !predictions) return { total: 0, breakdown: [] };

  const breakdown = [];
  let total = 0;

  const scoreStage = (key, pts) => {
    const userPicks    = (predictions[key] || []).filter(Boolean);
    const officialPicks = (results[key] || []).filter(Boolean);
    if (!officialPicks.length) return;

    const officialIds = new Set(officialPicks.map((t) => t.id));
    const correct = userPicks.filter((t) => officialIds.has(t.id)).length;
    const stagePts = correct * pts;
    total += stagePts;
    breakdown.push({
      stage: key,
      pts: stagePts,
      correct,
      possible: officialPicks.length * pts,
    });
  };

  scoreStage("r32Winners", STAGE_POINTS.r32Winners);
  scoreStage("r16Winners", STAGE_POINTS.r16Winners);
  scoreStage("qfWinners",  STAGE_POINTS.qfWinners);
  scoreStage("sfWinners",  STAGE_POINTS.sfWinners);

  // Final winner (array of 1)
  const userFinal     = (predictions.final || [])[0];
  const officialFinal = (results.final     || [])[0];
  if (officialFinal) {
    const finalPts = userFinal?.id === officialFinal.id ? STAGE_POINTS.final : 0;
    total += finalPts;
    breakdown.push({ stage: "final", pts: finalPts, correct: finalPts ? 1 : 0, possible: STAGE_POINTS.final });

    // Champion bonus
    if (userFinal?.id === officialFinal.id) {
      total += 32;
      breakdown.push({ stage: "champion", pts: 32, correct: 1, possible: 32 });
    }
  }

  return { total, breakdown };
}

/**
 * Count how many picks a user has made total (completeness indicator).
 */
export function countPicks(predictions) {
  const r32 = (predictions.r32Winners || []).filter(Boolean).length;
  const r16 = (predictions.r16Winners || []).filter(Boolean).length;
  const qf  = (predictions.qfWinners  || []).filter(Boolean).length;
  const sf  = (predictions.sfWinners  || []).filter(Boolean).length;
  const fin = (predictions.final       || []).filter(Boolean).length;
  return { r32, r16, qf, sf, fin, total: r32 + r16 + qf + sf + fin };
}

export const MAX_POINTS = 112;
export const STAGE_LABELS = {
  r32Winners: "Round of 32",
  r16Winners: "Round of 16",
  qfWinners:  "Quarter-Finals",
  sfWinners:  "Semi-Finals",
  final:      "Final",
  champion:   "Champion Bonus",
};
