import { useState, useEffect, useCallback, useRef } from "react";
import {
  collection,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  onSnapshot,
  serverTimestamp,
  query,
  orderBy,
} from "firebase/firestore";
import { db } from "../firebase";

export function useBrackets(uid) {
  const [brackets, setBrackets] = useState([]);
  const [bracketsLoading, setBracketsLoading] = useState(true);
  const [activeBracketId, setActiveBracketId] = useState(null);

  // Stable ref for debounce timers — not recreated on render
  const debounceRef = useRef({});

  useEffect(() => {
    if (!uid) {
      setBrackets([]);
      setBracketsLoading(false);
      return;
    }

    const q = query(
      collection(db, "users", uid, "brackets"),
      orderBy("createdAt", "asc")
    );
    const unsub = onSnapshot(q, (snap) => {
      const docs = snap.docs.map((d) => ({ id: d.id, ...d.data() }));
      setBrackets(docs);
      setBracketsLoading(false);
      setActiveBracketId((prev) => prev || (docs[0]?.id ?? null));
    });
    return unsub;
  }, [uid]);

  const activeBracket = brackets.find((b) => b.id === activeBracketId) || null;

  const createBracket = useCallback(
    async (name) => {
      if (!uid) return null;
      const ref = await addDoc(collection(db, "users", uid, "brackets"), {
        name: name.trim() || "New Bracket",
        predictions: {},
        locked: false,
        createdAt: serverTimestamp(),
      });
      setActiveBracketId(ref.id);
      return ref.id;
    },
    [uid]
  );

  const renameBracket = useCallback(
    async (id, name) => {
      if (!uid) return;
      await updateDoc(doc(db, "users", uid, "brackets", id), {
        name: name.trim(),
      });
    },
    [uid]
  );

  const deleteBracket = useCallback(
    async (id) => {
      if (!uid) return;
      await deleteDoc(doc(db, "users", uid, "brackets", id));
      setActiveBracketId((prev) => {
        if (prev !== id) return prev;
        // find next bracket from current state
        setBrackets((cur) => {
          const remaining = cur.filter((b) => b.id !== id);
          setActiveBracketId(remaining[0]?.id ?? null);
          return cur;
        });
        return prev; // will be overwritten by the setBrackets callback
      });
    },
    [uid]
  );

  const updatePredictions = useCallback(
    (id, stageId, data) => {
      // Read latest brackets from ref to avoid stale closure
      setBrackets((current) => {
        const bracket = current.find((b) => b.id === id);
        if (!bracket || bracket.locked || !uid) return current;

        const next = { ...(bracket.predictions || {}), [stageId]: data };

        // Debounced Firestore write
        if (debounceRef.current[id]) clearTimeout(debounceRef.current[id]);
        debounceRef.current[id] = setTimeout(() => {
          updateDoc(doc(db, "users", uid, "brackets", id), {
            predictions: next,
          });
        }, 800);

        // Optimistic local update
        return current.map((b) =>
          b.id === id ? { ...b, predictions: next } : b
        );
      });
    },
    [uid]
  );

  const lockBracket = useCallback(
    async (id) => {
      if (!uid) return;
      await updateDoc(doc(db, "users", uid, "brackets", id), { locked: true });
    },
    [uid]
  );

  return {
    brackets,
    bracketsLoading,
    activeBracketId,
    activeBracket,
    setActiveBracketId,
    createBracket,
    renameBracket,
    deleteBracket,
    updatePredictions,
    lockBracket,
  };
}
