import React, { useState } from "react";
import { GROUPS } from "../../data/teams";
import {
  buildR32Matchups,
  buildR16Matchups,
  buildQFMatchups,
  buildSFMatchups,
  buildFinalMatchup,
} from "../../utils/bracket";
import "./BracketView.css";

/**
 * BracketView — visual tournament bracket from R32 → Final,
 * plus a collapsible group stage summary above.
 *
 * Layout (left-to-right):
 *   R32 (col 0) → R16 (col 1) → QF (col 2) → SF (col 3) → Final (col 4) → SF (col 5) → QF (col 6) → R16 (col 7) → R32 (col 8)
 *
 * The bracket is split into two halves (top/bottom) that converge at the Final.
 * Top half:  M89,M90,M91,M92 → M97,M98 → M101 → M103
 * Bottom half: M93,M94,M95,M96 → M99,M100 → M102
 *
 * R32 feeds each R16 match in pairs:
 *   M89 ← M74,M77  |  M90 ← M73,M75
 *   M91 ← M76,M78  |  M92 ← M79,M80
 *   M93 ← M83,M84  |  M94 ← M81,M82
 *   M95 ← M86,M88  |  M96 ← M85,M87
 */
export default function BracketView({
  predictions,
  bracketName,
  brackets = [],
  activeBracketId,
  onSwitchBracket,
}) {
  const [showGroups, setShowGroups] = useState(false);

  // ── Derive all matchups ──────────────────────────────────────
  const groupPreds = predictions.group || {};
  const r32Thirds = predictions.r32Thirds || [];
  const r32Winners = predictions.r32Winners || [];
  const r16Winners = predictions.r16Winners || [];
  const qfWinners = predictions.qfWinners || [];
  const sfWinners = predictions.sfWinners || [];
  const finalPreds = predictions.final || [];

  const r32 = buildR32Matchups(groupPreds, r32Thirds);
  const r16 = buildR16Matchups(r32Winners);
  const qf = buildQFMatchups(r16Winners);
  const sf = buildSFMatchups(qfWinners);
  const fin = buildFinalMatchup(sfWinners);

  const champion = finalPreds[0] || null;

  // R32 match winners (indexed 0-15 = m73-m88)
  const r32W = (i) => r32Winners[i] || null;
  // R16 match winners (indexed 0-7 = m89-m96)
  const r16W = (i) => r16Winners[i] || null;
  // QF match winners  (indexed 0-3 = m97-m100)
  const qfW = (i) => qfWinners[i] || null;
  // SF match winners  (indexed 0-1 = m101-m102)
  const sfW = (i) => sfWinners[i] || null;

  // ── Group stage summary data ─────────────────────────────────
  const groupTeams = GROUPS.flatMap((g) =>
    (groupPreds[g] || [])
      .filter(Boolean)
      .map((t) => ({ ...t, groupLabel: `Group ${g}` }))
  );
  const thirds = r32Thirds.filter(Boolean);

  const hasAnyBracket = r32Winners.some(Boolean) || r16Winners.some(Boolean);

  return (
    <section className="bv">
      <div className="section-header">
        <div className="bv__header-row">
          <h2 className="section-header__title">
            {bracketName ? `📋 ${bracketName}` : "My Bracket"}
          </h2>
          {brackets.length > 1 && (
            <div className="bv__switcher">
              {brackets.map((b) => (
                <button
                  key={b.id}
                  className={`bv__switcher-btn${
                    b.id === activeBracketId ? " bv__switcher-btn--active" : ""
                  }`}
                  onClick={() => onSwitchBracket(b.id)}
                  title={b.locked ? `${b.name} (locked)` : b.name}
                >
                  {b.locked && <span className="bv__switcher-lock">🔒</span>}
                  {b.name}
                </button>
              ))}
            </div>
          )}
        </div>
        <p className="section-header__sub">
          Visual bracket from Round of 32 to the Final.
        </p>
      </div>

      {/* Champion banner */}
      {champion && (
        <div className="bv__champion">
          <span className="bv__champion-trophy">🏆</span>
          <div>
            <p className="bv__champion-label">2026 World Cup Champion</p>
            <p className="bv__champion-name">
              {champion.flag} {champion.name}
            </p>
          </div>
        </div>
      )}

      {/* Group stage collapsible */}
      {groupTeams.length > 0 && (
        <div className="bv__groups-panel">
          <button
            className="bv__groups-toggle"
            onClick={() => setShowGroups((o) => !o)}
          >
            <span>
              ⚽ Group Stage Summary{" "}
              <span className="bv__groups-badge">
                {groupTeams.length} picks
              </span>
            </span>
            <span>{showGroups ? "▲" : "▼"}</span>
          </button>
          {showGroups && (
            <div className="bv__groups-body">
              <div className="bv__groups-grid">
                {GROUPS.map((g) => {
                  const slots = groupPreds[g] || [];
                  const labels = ["1st", "2nd", "3rd"];
                  return (
                    <div key={g} className="bv__group-col">
                      <div className="bv__group-title">Group {g}</div>
                      {[0, 1, 2].map((i) => (
                        <div
                          key={i}
                          className={`bv__group-team${
                            slots[i] ? "" : " bv__group-team--empty"
                          }`}
                        >
                          {slots[i] ? (
                            <>
                              {slots[i].flag} {slots[i].name}{" "}
                              <span className="bv__group-rank">
                                {labels[i]}
                              </span>
                            </>
                          ) : (
                            <span className="bv__group-tbd">
                              {labels[i]} TBD
                            </span>
                          )}
                        </div>
                      ))}
                    </div>
                  );
                })}
              </div>
              {thirds.length > 0 && (
                <div className="bv__thirds">
                  <span className="bv__thirds-label">
                    Best 3rd-place qualifiers:
                  </span>
                  {thirds.map((t, i) => (
                    <span key={`t-${t.id}-${i}`} className="view-badge">
                      {t.flag} {t.name}
                    </span>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ── Visual bracket ── */}
      {!hasAnyBracket && (
        <div className="empty-state" style={{ marginTop: "2rem" }}>
          <span className="empty-state__icon">🏟️</span>
          <h3 className="empty-state__title">Bracket not started</h3>
          <p className="empty-state__body">
            Complete the Round of 32 tab to see your visual bracket.
          </p>
        </div>
      )}

      {hasAnyBracket && (
        <div className="bv__bracket-scroll">
          <div className="bv__bracket">
            {/* ════ LEFT HALF ════ */}
            {/* R32 — left column (matches 73,74,75,76 / 77,78,79,80) */}
            <div className="bv__col bv__col--r32">
              <div className="bv__col-label">Round of 32</div>
              <div className="bv__col-matches">
                {/* Top quarter */}
                <BracketMatch match={r32[0]} winner={r32W(0)} compact />
                <BracketMatch match={r32[1]} winner={r32W(1)} compact />
                <div className="bv__spacer" />
                <BracketMatch match={r32[2]} winner={r32W(2)} compact />
                <BracketMatch match={r32[3]} winner={r32W(3)} compact />
                <div className="bv__spacer--lg" />
                {/* Bottom quarter */}
                <BracketMatch match={r32[4]} winner={r32W(4)} compact />
                <BracketMatch match={r32[5]} winner={r32W(5)} compact />
                <div className="bv__spacer" />
                <BracketMatch match={r32[6]} winner={r32W(6)} compact />
                <BracketMatch match={r32[7]} winner={r32W(7)} compact />
              </div>
            </div>

            {/* R16 — left */}
            <div className="bv__col bv__col--r16">
              <div className="bv__col-label">Round of 16</div>
              <div className="bv__col-matches bv__col-matches--r16-left">
                <BracketMatch match={r16[0]} winner={r16W(0)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[1]} winner={r16W(1)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[2]} winner={r16W(2)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[3]} winner={r16W(3)} />
              </div>
            </div>

            {/* QF — left */}
            <div className="bv__col bv__col--qf">
              <div className="bv__col-label">Quarter-Finals</div>
              <div className="bv__col-matches bv__col-matches--qf-left">
                <BracketMatch match={qf[0]} winner={qfW(0)} />
                <div className="bv__spacer--xl" />
                <BracketMatch match={qf[1]} winner={qfW(1)} />
              </div>
            </div>

            {/* SF — left */}
            <div className="bv__col bv__col--sf">
              <div className="bv__col-label">Semi-Finals</div>
              <div className="bv__col-matches bv__col-matches--sf-left">
                <BracketMatch match={sf[0]} winner={sfW(0)} />
              </div>
            </div>

            {/* Final — center */}
            <div className="bv__col bv__col--final">
              <div className="bv__col-label bv__col-label--final">
                🏆 Final · M103
              </div>
              <div className="bv__col-matches bv__col-matches--final">
                <BracketMatch match={fin[0]} winner={champion} isFinal />

                {/* Champion display — shown in bracket center */}
                {champion ? (
                  <div className="bv__center-champion">
                    <div className="bv__center-champion__crown">🏆</div>
                    <div className="bv__center-champion__flag">
                      {champion.flag}
                    </div>
                    <div className="bv__center-champion__name">
                      {champion.name}
                    </div>
                    <div className="bv__center-champion__label">
                      2026 Champion
                    </div>
                  </div>
                ) : (
                  <div className="bv__center-tbd">
                    <div className="bv__center-tbd__icon">🏆</div>
                    <div className="bv__center-tbd__text">Champion TBD</div>
                  </div>
                )}
              </div>
              <div className="bv__final-date">
                July 19 · MetLife Stadium, NJ
              </div>
            </div>

            {/* SF — right */}
            <div className="bv__col bv__col--sf bv__col--right">
              <div className="bv__col-label">Semi-Finals</div>
              <div className="bv__col-matches bv__col-matches--sf-right">
                <BracketMatch match={sf[1]} winner={sfW(1)} />
              </div>
            </div>

            {/* QF — right */}
            <div className="bv__col bv__col--qf bv__col--right">
              <div className="bv__col-label">Quarter-Finals</div>
              <div className="bv__col-matches bv__col-matches--qf-right">
                <BracketMatch match={qf[2]} winner={qfW(2)} />
                <div className="bv__spacer--xl" />
                <BracketMatch match={qf[3]} winner={qfW(3)} />
              </div>
            </div>

            {/* R16 — right */}
            <div className="bv__col bv__col--r16 bv__col--right">
              <div className="bv__col-label">Round of 16</div>
              <div className="bv__col-matches bv__col-matches--r16-right">
                <BracketMatch match={r16[4]} winner={r16W(4)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[5]} winner={r16W(5)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[6]} winner={r16W(6)} />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r16[7]} winner={r16W(7)} />
              </div>
            </div>

            {/* R32 — right column (matches 81-88) */}
            <div className="bv__col bv__col--r32 bv__col--right">
              <div className="bv__col-label">Round of 32</div>
              <div className="bv__col-matches">
                <BracketMatch match={r32[8]} winner={r32W(8)} compact />
                <BracketMatch match={r32[9]} winner={r32W(9)} compact />
                <div className="bv__spacer" />
                <BracketMatch match={r32[10]} winner={r32W(10)} compact />
                <BracketMatch match={r32[11]} winner={r32W(11)} compact />
                <div className="bv__spacer--lg" />
                <BracketMatch match={r32[12]} winner={r32W(12)} compact />
                <BracketMatch match={r32[13]} winner={r32W(13)} compact />
                <div className="bv__spacer" />
                <BracketMatch match={r32[14]} winner={r32W(14)} compact />
                <BracketMatch match={r32[15]} winner={r32W(15)} compact />
              </div>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

/* ── Single match card ───────────────────────────────────────── */
function BracketMatch({ match, winner, compact, isFinal }) {
  if (!match) return <div className="bv-match bv-match--empty" />;

  const home = match.home || null;
  const away = match.away || null;
  const homeWon = winner && home && winner.id === home.id;
  const awayWon = winner && away && winner.id === away.id;

  return (
    <div
      className={`bv-match${compact ? " bv-match--compact" : ""}${
        isFinal ? " bv-match--final" : ""
      }`}
    >
      <div className="bv-match__no">M{match.matchNo}</div>
      <BracketTeam
        team={home}
        isWinner={homeWon}
        hasWinner={!!winner}
        compact={compact}
        placeholder={match.homeRole || match.homeLabel}
      />
      <div className="bv-match__divider" />
      <BracketTeam
        team={away}
        isWinner={awayWon}
        hasWinner={!!winner}
        compact={compact}
        placeholder={match.awayRole || match.awayLabel}
      />
    </div>
  );
}

function BracketTeam({ team, isWinner, hasWinner, compact, placeholder }) {
  if (!team) {
    return (
      <div className="bv-team bv-team--tbd">
        <span className="bv-team__tbd">
          {compact ? "TBD" : placeholder || "TBD"}
        </span>
      </div>
    );
  }
  return (
    <div
      className={`bv-team${isWinner ? " bv-team--winner" : ""}${
        hasWinner && !isWinner ? " bv-team--loser" : ""
      }`}
    >
      <span className="bv-team__flag">{team.flag}</span>
      <span className="bv-team__name">
        {compact ? team.name.split(" ")[0] : team.name}
      </span>
      {isWinner && <span className="bv-team__tick">✓</span>}
    </div>
  );
}
